50→      const token = path.replace('/offer/', '');
51→      router.push(`/offer/${token}`);
52→    } else if (path.includes('/customer/dashboard')) {
53→      router.replace('/(tabs)/');
54→    } else if (path.includes('/customer/cards')) {
55→      router.push('/(tabs)/cards/');
56→    } else {
57→      router.replace('/(tabs)/');
58→    }
